props.extensibilityCode:
// InputOTP com pattern alfanumérico e autoComplete
import { REGEXP_ONLY_DIGITS_AND_CHARS } from "input-otp";

<InputOTP
  maxLength={6}
  pattern={REGEXP_ONLY_DIGITS_AND_CHARS}
  autoComplete="one-time-code"
  inputMode="text"
  value={code}
  onChange={setCode}
  onComplete={(v) => verify(v)}
>
  {/* slots */}
</InputOTP>

tokens.customizationCode:
/* Slot maior para conteúdo touch-friendly */
[data-slot='input-otp-slot'] {
  width: 48px;
  height: 48px;
  font-size: 1.125rem;
}

